#include <iostream>
#include <iomanip>
#include <string>
using namespace std;
int main() {
    int roll;
    string name;
    double marks[5], total = 0;
    cin >> roll;
    cin.ignore();
    getline(cin, name);
    for (int i = 0; i < 5; i++) {
        cin >> marks[i];
        total += marks[i];
    }
    cout << "Roll Number: " << roll << endl;
    cout << "Student Name: " << name << endl;
    cout << "--------------------------" << endl;
    cout << fixed << setprecision(2);
    for (int i = 0; i < 5; i++) {
        cout << "Subject " << i + 1 << ":" << setw(13) << marks[i] << endl;
    }
    cout << "--------------------------" << endl;
    cout << "Total:" << setw(16) << total << endl;
    cout << "Percentage:" << setw(11) << (total / 5.0) << "%" << endl;
    return 0;
}

